from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple
import unittest


# ─── Domain Models ───────────────────────────────────────────────────────────

@dataclass
class Expense:
    """Represents a single expense entry."""
    category: str
    amount: float
    description: str = ""

    def __post_init__(self):
        if self.amount < 0:
            raise ValueError("Expense amount cannot be negative")
        if not self.category or not self.category.strip():
            raise ValueError("Category cannot be empty")
        self.category = self.category.strip().lower()


@dataclass
class UserAccount:
    """Represents a user account with expenses and budget tracking."""
    username: str
    expenses: List[Expense] = field(default_factory=list)

    def add_expense(self, category: str, amount: float, description: str = "") -> Expense:
        expense = Expense(category=category, amount=amount, description=description)
        self.expenses.append(expense)
        return expense

    def get_total_expenses(self) -> float:
        return sum(e.amount for e in self.expenses)

    def get_expenses_by_category(self) -> Dict[str, float]:
        breakdown: Dict[str, float] = {}
        for expense in self.expenses:
            breakdown[expense.category] = breakdown.get(expense.category, 0) + expense.amount
        return breakdown


# ─── Core Engine ─────────────────────────────────────────────────────────────

class MultiAgentBudgetOptimizer:
    """
    Collaborative budget management system for multiple users.
    Supports expense tracking, budget limits, dashboards, and optimization.
    """

    def __init__(self):
        self.users: Dict[str, UserAccount] = {}
        self.budget_limits: Dict[str, float] = {}
        self.total_budget: float = 0.0

    # ── User Management ──────────────────────────────────────────────────

    def add_user(self, username: str) -> UserAccount:
        if not username or not username.strip():
            raise ValueError("Username cannot be empty")
        username = username.strip()
        if username in self.users:
            raise ValueError(f"User '{username}' already exists")
        account = UserAccount(username=username)
        self.users[username] = account
        return account

    def get_user(self, username: str) -> UserAccount:
        if username not in self.users:
            raise KeyError(f"User '{username}' not found")
        return self.users[username]

    # ── Budget Limits ────────────────────────────────────────────────────

    def set_total_budget(self, amount: float) -> None:
        if amount < 0:
            raise ValueError("Total budget cannot be negative")
        self.total_budget = amount

    def set_category_budget(self, category: str, amount: float) -> None:
        if not category or not category.strip():
            raise ValueError("Category cannot be empty")
        if amount < 0:
            raise ValueError("Budget limit cannot be negative")
        self.budget_limits[category.strip().lower()] = amount

    def adjust_category_budget(self, category: str, new_amount: float) -> float:
        category = category.strip().lower()
        if category not in self.budget_limits:
            raise KeyError(f"No budget set for category '{category}'")
        if new_amount < 0:
            raise ValueError("Budget limit cannot be negative")
        old = self.budget_limits[category]
        self.budget_limits[category] = new_amount
        return old

    def get_category_budget(self, category: str) -> float:
        category = category.strip().lower()
        if category not in self.budget_limits:
            raise KeyError(f"No budget set for category '{category}'")
        return self.budget_limits[category]

    # ── Expense Input ────────────────────────────────────────────────────

    def input_expense(self, username: str, category: str, amount: float,
                      description: str = "") -> Expense:
        user = self.get_user(username)
        return user.add_expense(category, amount, description)

    # ── Dashboard / Summary ──────────────────────────────────────────────

    def get_group_total_expenses(self) -> float:
        return sum(user.get_total_expenses() for user in self.users.values())

    def get_remaining_budget(self) -> float:
        return self.total_budget - self.get_group_total_expenses()

    def get_group_expenses_by_category(self) -> Dict[str, float]:
        combined: Dict[str, float] = {}
        for user in self.users.values():
            for cat, amt in user.get_expenses_by_category().items():
                combined[cat] = combined.get(cat, 0) + amt
        return combined

    def get_individual_contributions(self) -> Dict[str, float]:
        return {name: user.get_total_expenses() for name, user in self.users.items()}

    def get_category_remaining(self) -> Dict[str, float]:
        """Returns remaining budget per category."""
        group_by_cat = self.get_group_expenses_by_category()
        remaining: Dict[str, float] = {}
        for cat, limit in self.budget_limits.items():
            spent = group_by_cat.get(cat, 0)
            remaining[cat] = limit - spent
        return remaining

    def get_over_budget_categories(self) -> Dict[str, float]:
        """Returns categories that are over budget with the overage amount."""
        over: Dict[str, float] = {}
        for cat, rem in self.get_category_remaining().items():
            if rem < 0:
                over[cat] = abs(rem)
        return over

    def get_dashboard(self) -> Dict:
        """Returns a complete financial dashboard summary."""
        return {
            "total_budget": self.total_budget,
            "total_expenses": self.get_group_total_expenses(),
            "remaining_budget": self.get_remaining_budget(),
            "expenses_by_category": self.get_group_expenses_by_category(),
            "category_budgets": dict(self.budget_limits),
            "category_remaining": self.get_category_remaining(),
            "individual_contributions": self.get_individual_contributions(),
            "over_budget_categories": self.get_over_budget_categories(),
            "user_count": len(self.users),
        }

    # ── Optimization Engine ──────────────────────────────────────────────

    def optimize_spending(self) -> List[str]:
        """
        Analyzes group spending and produces actionable suggestions to
        reduce expenses or reallocate funds to meet financial goals.
        """
        suggestions: List[str] = []
        total_expenses = self.get_group_total_expenses()
        remaining = self.get_remaining_budget()
        group_by_cat = self.get_group_expenses_by_category()
        contributions = self.get_individual_contributions()

        # 1. Overall budget warning
        if remaining < 0:
            suggestions.append(
                f"CRITICAL: Group is over total budget by ${abs(remaining):.2f}. "
                f"Immediate spending reduction required."
            )
        elif self.total_budget > 0 and remaining < self.total_budget * 0.1:
            suggestions.append(
                f"WARNING: Only ${remaining:.2f} remaining "
                f"({remaining / self.total_budget * 100:.1f}% of budget). "
                f"Consider reducing discretionary spending."
            )

        # 2. Category-level over-budget alerts with reallocation suggestions
        over_budget = self.get_over_budget_categories()
        under_budget_cats = {
            cat: rem for cat, rem in self.get_category_remaining().items() if rem > 0
        }

        for cat, overage in over_budget.items():
            suggestions.append(
                f"Category '{cat}' is over budget by ${overage:.2f}. "
                f"Reduce spending or reallocate from surplus categories."
            )
            # Suggest reallocation from under-budget categories
            for donor_cat, surplus in under_budget_cats.items():
                if surplus >= overage:
                    suggestions.append(
                        f"  -> Reallocate ${overage:.2f} from '{donor_cat}' "
                        f"(surplus: ${surplus:.2f}) to '{cat}'."
                    )
                    break

        # 3. Identify highest spenders for equitable distribution
        if len(contributions) > 1 and total_expenses > 0:
            avg_contribution = total_expenses / len(contributions)
            for user, amount in contributions.items():
                if amount > avg_contribution * 1.5:
                    suggestions.append(
                        f"User '{user}' is spending significantly above average "
                        f"(${amount:.2f} vs avg ${avg_contribution:.2f}). "
                        f"Consider redistributing shared expenses."
                    )

        # 4. Identify highest spending category for reduction tips
        if group_by_cat:
            top_cat = max(group_by_cat, key=group_by_cat.get)
            top_pct = (group_by_cat[top_cat] / total_expenses * 100) if total_expenses > 0 else 0
            if top_pct > 40:
                suggestions.append(
                    f"Category '{top_cat}' accounts for {top_pct:.1f}% of total spending. "
                    f"Diversifying expenses may reveal savings opportunities."
                )

        # 5. Categories with no budget set
        unbudgeted = [c for c in group_by_cat if c not in self.budget_limits]
        if unbudgeted:
            suggestions.append(
                f"Categories without budget limits: {', '.join(unbudgeted)}. "
                f"Setting limits helps track and control spending."
            )

        if not suggestions:
            suggestions.append("All spending is within budget. No optimization needed.")

        return suggestions

    def suggest_reallocation(self) -> List[Tuple[str, str, float]]:
        """
        Returns a list of (from_category, to_category, amount) tuples
        suggesting fund reallocations to cover over-budget categories.
        """
        reallocations: List[Tuple[str, str, float]] = []
        over_budget = self.get_over_budget_categories()
        under_budget = {
            cat: rem for cat, rem in self.get_category_remaining().items() if rem > 0
        }

        for deficit_cat, overage in sorted(over_budget.items(), key=lambda x: -x[1]):
            needed = overage
            for surplus_cat in sorted(under_budget, key=lambda c: -under_budget[c]):
                if needed <= 0:
                    break
                available = under_budget[surplus_cat]
                transfer = min(needed, available)
                if transfer > 0:
                    reallocations.append((surplus_cat, deficit_cat, round(transfer, 2)))
                    under_budget[surplus_cat] -= transfer
                    needed -= transfer

        return reallocations


